// Extract order and product data
const body = $input.first().json.body;
const order = body.order || {};
const products = body.products || [];

if (products.length === 0) {
  throw new Error('No products provided for asset compilation');
}

// Create individual items for each product
return products.map(product => ({
  json: {
    ...product,
    order_id: order.order_id,
    customer_name: order.customer_name,
    customer_email: order.customer_email
  }
}));

// Compile digital assets for each product
const product = $input.first().json;

// Parse image and video URLs
let imageUrls = [];
let videoUrls = [];

try {
  if (product.image_urls) {
    imageUrls = Array.isArray(product.image_urls) ? product.image_urls : JSON.parse(product.image_urls);
  }
} catch (e) {
  console.error('Failed to parse image_urls:', e);
}

try {
  if (product.video_urls) {
    videoUrls = Array.isArray(product.video_urls) ? product.video_urls : JSON.parse(product.video_urls);
  }
} catch (e) {
  console.error('Failed to parse video_urls:', e);
}

// Convert HTML description to plain text
const stripHtml = (html) => {
  if (!html) return '';
  return html.replace(/<[^>]*>/g, '').replace(/\s+/g, ' ').trim();
};

const plainDescription = stripHtml(product.description || product.Copy_html);

return [{
  json: {
    sku: product.sku,
    name: product.name || product.Name,
    quantity: product.quantity || 1,
    images: imageUrls,
    videos: videoUrls,
    description: plainDescription,
    description_html: product.description || product.Copy_html,
    tagline: product.tagline || product.Tagline,
    order_id: product.order_id,
    customer_name: product.customer_name,
    customer_email: product.customer_email,
    asset_count: imageUrls.length + videoUrls.length,
    compiled_at: new Date().toISOString()
  }
}];

// Aggregate all products into a single package
const allProducts = $input.all();

if (allProducts.length === 0) {
  throw new Error('No products to package');
}

const firstProduct = allProducts[0].json;

const packageData = {
  order_id: firstProduct.order_id,
  customer: {
    name: firstProduct.customer_name,
    email: firstProduct.customer_email
  },
  products: allProducts.map(p => p.json),
  total_products: allProducts.length,
  total_assets: allProducts.reduce((sum, p) => sum + (p.json.asset_count || 0), 0),
  package_created_at: new Date().toISOString()
};

return [{ json: packageData }];
